/**
 * Bread Rise — case studies.
 * Files live in /public/media/<slug>/. Each base name resolves into a
 * responsive trio of WebP variants generated by scripts/optimize-images.sh:
 *   <base>-200.webp / <base>-800.webp / <base>-1280.webp
 * The asset() helper prepends the GitHub Pages basePath at runtime.
 */

import { asset } from "@/lib/utils";

const ASPECT_W = 1280;
const ASPECT_H = 1715; // 1280×1715 ≈ 3:4 portrait used by every photo.

export type ImgSrc = {
  /** Default `src` — the 800w variant works as the fallback. */
  src: string;
  /** Tiny thumb (~200w) for clusters and offscreen plates. */
  thumb: string;
  /** Full responsive `srcset` covering 200 / 800 / 1280 widths. */
  srcSet: string;
  /** Intrinsic aspect ratio in pixels — set as width/height on `<img>`. */
  width: number;
  height: number;
};

function img(slug: string, base: string): ImgSrc {
  const v = (size: 200 | 800 | 1280) =>
    asset(`/media/${slug}/${base}-${size}.webp`);
  return {
    src: v(800),
    thumb: v(200),
    srcSet: `${v(200)} 200w, ${v(800)} 800w, ${v(1280)} 1280w`,
    width: ASPECT_W,
    height: ASPECT_H,
  };
}

export type Project = {
  id: string;
  index: string;
  title: string;
  client?: string;
  year: number;
  discipline: string[];
  /** Service tags shown on the project detail page. */
  services?: string[];
  /** Long-form description. Use \n\n between paragraphs. */
  description?: string;
  /** Optional bullet list rendered under "Visual signatures". */
  visualSignatures?: string[];
  /** Optional bullet list rendered under "Designed for". */
  designedFor?: string[];
  /** First image is also used as the cover/headline plate. */
  gallery: ImgSrc[];
};

