export type Plate = {
  key: string;
  image: ImgSrc;
  projectId: string;
  projectTitle: string;
  projectIndex: string;
  /** Filename label rendered under the References cluster thumbnails. */
  fileLabel: string;
};

function fileLabelFor(image: ImgSrc): string {
  // strip the responsive `-800` suffix and the extension so the label
  // matches the source filename ("IMG_3393").
  const last = image.src.split("/").pop() ?? image.src;
  return last.replace(/-(?:200|800|1280)\.webp$/i, "");
}

/**
 * Flat list of every project image, tagged with its parent project.
 * Used by the 3D stack and the References wall.
 */
export const plates: Plate[] = projects.flatMap((p) =>
  p.gallery.map((image, i) => ({
    key: `${p.id}-${i}`,
    image,
    projectId: p.id,
    projectTitle: p.title,
    projectIndex: p.index,
    fileLabel: fileLabelFor(image),
  })),
);

/**
 * 12 plates for the hero stack — distributed across all projects so
 * every project shows up at least once.
 */
export const stackPlates: Plate[] = (() => {
  const out: Plate[] = [];
  let i = 0;
  while (out.length < 12 && i < 50) {
    for (const p of projects) {
      const image = p.gallery[i];
      if (!image) continue;
      out.push({
        key: `${p.id}-stack-${i}`,
        image,
        projectId: p.id,
        projectTitle: p.title,
        projectIndex: p.index,
        fileLabel: fileLabelFor(image),
      });
      if (out.length >= 12) break;
    }
    i += 1;
  }
  return out;
})();

/** Project plates used by the References cluster. */
export const allReferencePlates: Plate[] = plates;
